/**
 * @fileoverview GridTable component definition for JIT pipeline.
 *
 * @module module/GridTable.def
 */

import razyui from '../index.js';import { PART } from './GridTable/constants.js';
/**
 * The definition object for the GridTable component.
 * Contains configuration for tokens, states, templates, variants, and custom elements.
 *
 * @type {Object}
 */
export const GridTableDef = {
    /**
     * The name of the component.
     * @type {string}
     */
    name: 'GridTable',
    
    /**
     * The custom element tag name for the component.
     * @type {string}
     */
    tag: 'rui-grid-table',

    /**
     * Design tokens specific to the GridTable component.
     * These tokens define the visual appearance of the component.
     */
    tokens: {
        prefix: 'gt',
        tokens: {
            'radius':              { ref: 'radius.md',           description: 'Container border radius' },
            'toolbar-padding':     { value: '0.5rem 1rem',      description: 'Toolbar padding' },
            'toolbar-font-size':   { value: '12px',             description: 'Toolbar font size' },
            'header-font-size':    { value: '13px',             description: 'Header font size' },
            'header-font-weight':  { value: '600',              description: 'Header font weight' },
            'cell-padding':        { value: '0 1rem',           description: 'Cell padding' },
            'cell-font-size':      { value: '12px',             description: 'Cell font size' },
            'filter-padding':      { value: '4px 6px',           description: 'Filter padding' },
            'filter-font-size':    { value: '12px',             description: 'Filter font size' },
            'group-font-size':     { value: '12px',             description: 'Group row font size' },
            'row-number-font-size':{ value: '11px',             description: 'Row number font size' },
            'accent':              { ref: 'color.accent',       description: 'Accent color' },
            'bg':                  { ref: 'color.bg',           description: 'Background' },
            'bg-active':           { ref: 'color.bg-active',    description: 'Active background' },
            'bg-hover':            { ref: 'color.bg-hover',     description: 'Hover background' },
            'bg-inset':            { ref: 'color.bg-inset',     description: 'Inset background' },
            'bg-raised':           { ref: 'color.bg-raised',    description: 'Raised background' },
            'border-color':        { ref: 'color.border',       description: 'Border color' },
            'border-strong':       { ref: 'color.border-strong',description: 'Strong border' },
            'font-stack':          { ref: 'font.family',        description: 'Font family' },
            'on-accent':           { ref: 'color.on-accent',    description: 'Text on accent' },
            'text-color':          { ref: 'color.text',         description: 'Text color' },
            'text-muted':          { ref: 'color.text-muted',   description: 'Muted text' },
            'text-secondary':      { ref: 'color.text-secondary',description: 'Secondary text' },
            'thumb':               { ref: 'color.thumb',        description: 'Scrollbar thumb' },
            'thumb-hover':         { ref: 'color.thumb-hover',  description: 'Scrollbar thumb hover' },
        },
    },

    /**
     * State machine configuration for the GridTable component.
     * Defines the possible states and transitions.
     */
    states: {
        initial: 'idle',
        states: {
            idle:      { on: { LOAD: 'loading', RESIZE: 'resizing', DRAG_COL: 'column-dragging' } },
            loading:   { on: { LOADED: 'idle', ERROR: 'idle' } },
            resizing:  { on: { RESIZE_END: 'idle' } },
            'column-dragging': { on: { DRAG_END: 'idle' } },
        },
        effects: {
            /**
             * Effect triggered when entering the 'loading' state.
             * Adds the 'is-data-loading' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            loading(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-data-loading');
            },
            /**
             * Effect triggered when exiting the 'loading' state.
             * Removes the 'is-data-loading' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'loading:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-data-loading');
            },
            /**
             * Effect triggered when entering the 'resizing' state.
             * Adds the 'is-resizing' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            resizing(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-resizing');
            },
            /**
             * Effect triggered when exiting the 'resizing' state.
             * Removes the 'is-resizing' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'resizing:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-resizing');
            },
            /**
             * Effect triggered when entering the 'column-dragging' state.
             * Adds the 'is-column-dragging' class to the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'column-dragging'(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-column-dragging');
            },
            /**
             * Effect triggered when exiting the 'column-dragging' state.
             * Removes the 'is-column-dragging' class from the element.
             *
             * @param {Object} ctx - The state context.
             * @param {HTMLElement} ctx.el - The component element.
             */
            'column-dragging:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-column-dragging');
            },
        },
    },

    /**
     * Template slot definitions for the GridTable component.
     * Defines the HTML structure and classes for different parts of the component.
     */
    template: {
        slots: {
            root:      { element: 'div', classes: ['grid-table-container'] },
            toolbar:   { element: 'div', classes: ['gt-toolbar'] },
            header:    { element: 'div', classes: ['gt-header'] },
            body:      { element: 'div', classes: ['gt-body'] },
            row:       { element: 'div', classes: ['gt-row'] },
            cell:      { element: 'div', classes: ['gt-cell'] },
            filter:    { element: 'div', classes: ['gt-filter'] },
            footer:    { element: 'div', classes: ['gt-footer'] },
            panel:     { element: 'div', classes: ['gt-panel'] },
        },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.MAIN]: PART.MAIN,
        [PART.WRAPPER]: PART.WRAPPER,
        [PART.TOOLBAR]: PART.TOOLBAR,
        [PART.HEADER]: PART.HEADER,
        [PART.HEADER_GROUPS]: PART.HEADER_GROUPS,
        [PART.HEADER_COLUMNS]: PART.HEADER_COLUMNS,
        [PART.GROUP_CELL]: PART.GROUP_CELL,
        [PART.TOOLSIDE]: PART.TOOLSIDE,
        [PART.PIN_LEFT]: PART.PIN_LEFT,
        [PART.PIN_RIGHT]: PART.PIN_RIGHT,
        [PART.CHECKBOX_COL]: PART.CHECKBOX_COL,
        [PART.RESIZER]: PART.RESIZER,
        [PART.LABEL]: PART.LABEL,
        [PART.SORT_ICON]: PART.SORT_ICON,
        [PART.MENU_ICON]: PART.MENU_ICON,
        [PART.DRAG_GHOST]: PART.DRAG_GHOST,
        [PART.FILTER_ROW]: PART.FILTER_ROW,
        [PART.FILTER_CELL]: PART.FILTER_CELL,
        [PART.FILTER_RESET]: PART.FILTER_RESET,
        [PART.FILTER_ICON]: PART.FILTER_ICON,
        [PART.BODY]: PART.BODY,
        [PART.VIEWPORT]: PART.VIEWPORT,
        [PART.SPACER]: PART.SPACER,
        [PART.ROWS]: PART.ROWS,
        [PART.ROW]: PART.ROW,
        [PART.DATA]: PART.DATA,
        [PART.ROW_DRAG_GHOST]: PART.ROW_DRAG_GHOST,
        [PART.CONTEXT_MENU]: PART.CONTEXT_MENU,
        [PART.CONTEXT_ITEM]: PART.CONTEXT_ITEM,
        [PART.CONTEXT_ICON]: PART.CONTEXT_ICON,
        [PART.CONTEXT_LABEL]: PART.CONTEXT_LABEL,
        [PART.CONTEXT_ARROW]: PART.CONTEXT_ARROW,
        [PART.CONTEXT_CHECK]: PART.CONTEXT_CHECK,
        [PART.CONTEXT_SUBMENU]: PART.CONTEXT_SUBMENU,
        [PART.CONTEXT_SEP]: PART.CONTEXT_SEP,
        [PART.VSCROLL]: PART.VSCROLL,
        [PART.HSCROLL]: PART.HSCROLL,
        [PART.PANEL_BAR]: PART.PANEL_BAR,
        [PART.BAR_BTN]: PART.BAR_BTN,
        [PART.SIDE_PANEL]: PART.SIDE_PANEL,
        [PART.PANEL_HEADER]: PART.PANEL_HEADER,
        [PART.PANEL_TITLE]: PART.PANEL_TITLE,
        [PART.PANEL_CLOSE]: PART.PANEL_CLOSE,
        [PART.PANEL_SEARCH]: PART.PANEL_SEARCH,
        [PART.PANEL_BODY]: PART.PANEL_BODY,
        [PART.PANEL_COLUMNS]: PART.PANEL_COLUMNS,
        [PART.COLUMN_LIST]: PART.COLUMN_LIST,
        [PART.COLUMN_ITEM]: PART.COLUMN_ITEM,
        [PART.COLUMN_DROP_IND]: PART.COLUMN_DROP_IND,
        [PART.COLUMN_GROUP]: PART.COLUMN_GROUP,
        [PART.COLUMN_GRIP]: PART.COLUMN_GRIP,
        [PART.FOOTER]: PART.FOOTER,
        [PART.FOOTER_INFO]: PART.FOOTER_INFO,
        [PART.FOOTER_NAV]: PART.FOOTER_NAV,
        [PART.FOOTER_DOTS]: PART.FOOTER_DOTS,
        [PART.EMPTY_MSG]: PART.EMPTY_MSG,
    },

    /* Vendor pseudo-elements only — cannot be expressed as JIT classes */
    styles: {
        '&-viewport::-webkit-scrollbar': {
            display: 'none',
        },
    },

    /**
     * Observed attributes for the custom element.
     * @type {string[]}
     */
    observedAttrs: ['data', 'columns', 'page-size', 'sortable'],
    
    /**
     * Mapping of observed attributes to component properties.
     * @type {Object<string, string>}
     */
    attrMap: {
        data: 'data',
        columns: 'columns',
        'page-size': 'pageSize',
        sortable: 'sortable',
    },
};

export default GridTableDef;
