/**
 * @fileoverview GridTable layout — column reflow, resize, auto-size,
 *               scrollable widths, group headers, filter row, scrollbars,
 *               and spacer management.
 *
 * Every exported function receives the thin `ctx` context bridge produced
 * by the class's `#ctx()` method (see index.js).
 *
 * @module module/GridTable/layout
 */

import razyui from '../../index.js';
import { DEFAULTS } from './constants.js';
import { getGroupBlocks } from './helpers.js';
import { buildGroupHeaders } from './view.js';


// ═════════════════════════════════════════════════════════════════
// Helper getters (pure computations on ctx)
// ═════════════════════════════════════════════════════════════════

/**
 * Total width of all visible columns.
 * @param {Object} ctx
 * @returns {number}
 */
export function getColumnsWidth(ctx) {
    return ctx.columnOrder.reduce((s, n) => s + (ctx.gridColumn[n]?.width || 0), 0);
}

/**
 * Visible columns that are NOT pinned left or right.
 * @param {Object} ctx
 * @returns {string[]}
 */
export function getScrollableColumns(ctx) {
    if (!ctx.pinnedLeft.length && !ctx.pinnedRight.length) return ctx.columnOrder;
    const pinSet = new Set([...ctx.pinnedLeft, ...ctx.pinnedRight]);
    return ctx.columnOrder.filter(n => !pinSet.has(n));
}

/**
 * Total width of scrollable (non-pinned) columns.
 * @param {Object} ctx
 * @returns {number}
 */
export function getScrollableColumnsWidth(ctx) {
    return getScrollableColumns(ctx).reduce((s, n) => s + (ctx.gridColumn[n]?.width || 0), 0);
}

/**
 * Viewport element width in pixels.
 * @param {Object} ctx
 * @returns {number}
 */
export function getViewportWidth(ctx) {
    return Math.max(0, ctx.viewport?.prop('clientWidth') || 0);
}

/**
 * Usable width of the scrollable data area (viewport minus fixed zones).
 * @param {Object} ctx
 * @returns {number}
 */
export function getDataAreaWidth(ctx) {
    return Math.max(0, getViewportWidth(ctx) - ctx.fixedLeftWidth - ctx.fixedRightWidth);
}

/**
 * Number of entries in the current display list.
 * @param {Object} ctx
 * @returns {number}
 */
export function getDisplayCount(ctx) {
    return ctx.displayList.length;
}

/**
 * Map a display-list index to its underlying data-array index.
 * @param {Object} ctx
 * @param {number} displayIdx
 * @returns {number}
 */
export function resolveDataIndex(ctx, displayIdx) {
    return ctx.displayList[displayIdx]?.dataIndex ?? displayIdx;
}


// ═════════════════════════════════════════════════════════════════
// Column group caches
// ═════════════════════════════════════════════════════════════════

/**
 * Return (and cache) a map of column-name → group-index.
 * @param {Object} ctx
 * @returns {Object}
 */
export function getGroupIndexMap(ctx) {
    if (ctx.grpIdxMapCache) return ctx.grpIdxMapCache;
    const map = {};
    ctx.columnGroups.forEach((g, i) => g.columns.forEach(c => { map[c] = i; }));
    ctx.grpIdxMapCache = map;
    return map;
}

/**
 * Return (and cache) the group header row element.
 * @param {Object} ctx
 * @returns {HTMLElement|null}
 */
export function getGroupRow(ctx) {
    if (ctx.grpRowCache !== undefined) return ctx.grpRowCache;
    ctx.grpRowCache = ctx.container.find('.grid-table-header-groups > .grid-table-row');
    return ctx.grpRowCache;
}


// ═════════════════════════════════════════════════════════════════
// recalcFixedLeft — recompute tool-side, pin, checkbox widths
// ═════════════════════════════════════════════════════════════════

/**
 * Recalculate CSS variable widths for pinned / tool-side / checkbox zones.
 * @param {Object} ctx
 */
export function recalcFixedLeft(ctx) {
    razyui.measure(() => {
        let tw = 0, tc = 0;
        if (ctx.showDragHandle) { tw += 24; tc++; }
        if (ctx.showRowNumbers) { tw += ctx.rowNumberWidth; tc++; }
        if (ctx.subRowFn)       { tw += 24; tc++; }
        if (tc > 0) { tw += (tc - 1) * 6; tw += 20; }
        if (ctx.maxSubRowDepth > 0) tw += ctx.maxSubRowDepth * 20;
        ctx.toolsideWidth = tw;

        ctx.checkboxColWidth = ctx.showCheckbox ? DEFAULTS.checkboxColWidth : 0;

        ctx.pinLeftWidth = 0;
        const visibleSet = new Set(ctx.columnOrder);
        ctx.pinnedLeft.forEach(n => {
            if (visibleSet.has(n)) ctx.pinLeftWidth += ctx.gridColumn[n]?.width || 0;
        });

        // Cap each pin zone to 30% of the viewport so pinned columns
        // don't consume too much space and leave nothing for scrollable data.
        const vpW = ctx.cachedViewportWidth || ctx.viewport?.prop('clientWidth') || 0;
        if (vpW > 0) {
            const maxPin = vpW * 0.3;

            // Clamp pin-left
            if (ctx.pinLeftWidth > maxPin && ctx.pinLeftWidth > 0) {
                const ratio = maxPin / ctx.pinLeftWidth;
                ctx.pinnedLeft.forEach(n => {
                    if (visibleSet.has(n) && ctx.gridColumn[n]) {
                        ctx.gridColumn[n].width = Math.max(
                            ctx.columnConfig[n]?.minWidth || ctx.minColumnWidth,
                            Math.floor(ctx.gridColumn[n].width * ratio),
                        );
                    }
                });
                ctx.pinLeftWidth = 0;
                ctx.pinnedLeft.forEach(n => {
                    if (visibleSet.has(n)) ctx.pinLeftWidth += ctx.gridColumn[n]?.width || 0;
                });
            }
        }

        ctx.fixedLeftWidth = ctx.toolsideWidth + ctx.pinLeftWidth + ctx.checkboxColWidth;

        ctx.pinRightWidth = 0;
        ctx.pinnedRight.forEach(n => {
            if (visibleSet.has(n)) ctx.pinRightWidth += ctx.gridColumn[n]?.width || 0;
        });

        // Clamp pin-right
        if (vpW > 0) {
            const maxPin = vpW * 0.3;
            if (ctx.pinRightWidth > maxPin && ctx.pinRightWidth > 0) {
                const ratio = maxPin / ctx.pinRightWidth;
                ctx.pinnedRight.forEach(n => {
                    if (visibleSet.has(n) && ctx.gridColumn[n]) {
                        ctx.gridColumn[n].width = Math.max(
                            ctx.columnConfig[n]?.minWidth || ctx.minColumnWidth,
                            Math.floor(ctx.gridColumn[n].width * ratio),
                        );
                    }
                });
                ctx.pinRightWidth = 0;
                ctx.pinnedRight.forEach(n => {
                    if (visibleSet.has(n)) ctx.pinRightWidth += ctx.gridColumn[n]?.width || 0;
                });
            }
        }

        ctx.fixedRightWidth = ctx.pinRightWidth;

        if (ctx.container) {
            razyui.mutate(() => {
                ctx.container.css('--toolside-width',    ctx.toolsideWidth + 'px');
                ctx.container.css('--pin-left-width',    ctx.pinLeftWidth + 'px');
                ctx.container.css('--pin-right-width',   ctx.pinRightWidth + 'px');
                ctx.container.css('--checkbox-col-width', ctx.checkboxColWidth + 'px');
                ctx.container.css('--fixed-left-width',  ctx.fixedLeftWidth + 'px');
                ctx.container.css('--row-number-width',  ctx.rowNumberWidth + 'px');
            });
        }
    });
}


// ═════════════════════════════════════════════════════════════════
// reflowColumns — full column layout recalculation
// ═════════════════════════════════════════════════════════════════

/**
 * Full column layout pass — assign widths, distribute grow, recompute
 * positions, update header/pool cells, sync group headers, filter row,
 * spacer, and scrollbars.
 * @param {Object} ctx
 */
export function reflowColumns(ctx) {
    razyui.measure(() => {
        const colOrder = ctx.columnOrder;
        const scrollable = getScrollableColumns(ctx);
        const vpW = getDataAreaWidth(ctx);
        const fullVpW = getViewportWidth(ctx);
        // Sync cached viewport width so reflowScrollableWidths uses latest value
        ctx.cachedViewportWidth = fullVpW;
        const _vp = ctx.viewport?.[0];
        const _scrollTop = _vp ? _vp.scrollTop : 0;
        const _scrollLeft = ctx.scrollLeft;
        const _vpH = _vp ? _vp.clientHeight : 0;
        updateHScrollbarCached(ctx);
        let totalW = 0;
        let totalGrow = 0;

        // 1. Assign initial widths from config or last known
        colOrder.forEach(name => {
            const cc = ctx.columnConfig[name];
            if (!ctx.gridColumn[name]) {
                ctx.gridColumn[name] = { position: 0, width: cc.width || cc.minWidth || ctx.minColumnWidth };
            }
            const g = ctx.gridColumn[name];
            g.width = Math.max(cc.minWidth, g.width || cc.width || cc.minWidth);
            totalW += g.width;
            totalGrow += (cc.grow || 0);
        });

        // 2. Distribute grow space among scrollable columns
        const scrollableW = scrollable.reduce((s, n) => s + (ctx.gridColumn[n]?.width || 0), 0);
        const extra = vpW - scrollableW;
        if (extra > 0 && totalGrow > 0) {
            scrollable.forEach(name => {
                const cc = ctx.columnConfig[name];
                if (cc.grow > 0) {
                    ctx.gridColumn[name].width += (cc.grow / totalGrow) * extra;
                }
            });
        }

        // 3. Shrink pass — if columns exceed viewport, shrink growable columns proportionally
        const scrollableW2 = scrollable.reduce((s, n) => s + (ctx.gridColumn[n]?.width || 0), 0);
        if (scrollableW2 > vpW && vpW > 0) {
            const excess = scrollableW2 - vpW;
            const shrinkable = scrollable.filter(n => {
                const cc = ctx.columnConfig[n];
                return cc.grow > 0 && ctx.gridColumn[n].width > cc.minWidth;
            });
            if (shrinkable.length) {
                const totalShrink = shrinkable.reduce((s, n) =>
                    s + (ctx.gridColumn[n].width - ctx.columnConfig[n].minWidth), 0);
                if (totalShrink > 0) {
                    const shrinkRatio = Math.min(1, excess / totalShrink);
                    shrinkable.forEach(n => {
                        const room = ctx.gridColumn[n].width - ctx.columnConfig[n].minWidth;
                        ctx.gridColumn[n].width -= room * shrinkRatio;
                    });
                }
            }
        }

        // 4. Compute left positions
        let left = 0;
        scrollable.forEach(name => {
            ctx.gridColumn[name].position = left;
            left += ctx.gridColumn[name].width;
        });

        // 4b. Determine which columns actually changed position or width
        const prev = ctx._prevColumnLayout || {};
        const dirtyScrollable = [];
        const dirtyPinLeft = [];
        const dirtyPinRight = [];
        scrollable.forEach(name => {
            const col = ctx.gridColumn[name];
            const p = prev[name];
            if (!p || Math.abs(p.position - col.position) > 0.01 || Math.abs(p.width - col.width) > 0.01) {
                dirtyScrollable.push(name);
            }
        });
        ctx.pinnedLeft.forEach(name => {
            const col = ctx.gridColumn[name];
            const p = prev[name];
            if (!p || Math.abs(p.width - col.width) > 0.01) dirtyPinLeft.push(name);
        });
        ctx.pinnedRight.forEach(name => {
            const col = ctx.gridColumn[name];
            const p = prev[name];
            if (!p || Math.abs(p.width - col.width) > 0.01) dirtyPinRight.push(name);
        });

        // Snapshot current layout for next comparison
        const snapshot = {};
        colOrder.forEach(name => {
            const col = ctx.gridColumn[name];
            snapshot[name] = { position: col.position, width: col.width };
        });
        ctx._prevColumnLayout = snapshot;

        const nothingChanged = !dirtyScrollable.length && !dirtyPinLeft.length && !dirtyPinRight.length;

        // 5. Update header + body cells
        razyui.mutate(() => {
            ctx.observerLocked = true;

            // Resolve header pin zones (siblings of headerRow inside header-columns)
            const headerParent = ctx.headerRow.parent()[0];
            const headerPinLeft  = headerParent?.querySelector(':scope > .grid-table-pin-left');
            const headerPinRight = headerParent?.querySelector(':scope > .grid-table-pin-right');

            dirtyScrollable.forEach(name => {
                const col = ctx.gridColumn[name];
                if (ctx.headerColumns[name]) {
                    const cellEl = ctx.headerColumns[name][0];
                    // Move back to scrollable zone if currently in a pin zone
                    if (cellEl && razyui(cellEl).parent()[0] !== ctx.headerRow[0]) {
                        ctx.headerRow.append(cellEl);
                    }
                    ctx.headerColumns[name].css('left', col.position + 'px').width(col.width);
                }
                ctx.poolCells.forEach(cells => {
                    if (cells[name]) cells[name].css('left', col.position + 'px').width(col.width);
                });
            });
            // Pinned-left columns — move header cells to pin-left zone
            dirtyPinLeft.forEach(name => {
                const col = ctx.gridColumn[name];
                if (!col) return;
                if (ctx.headerColumns[name]) {
                    const cellEl = ctx.headerColumns[name][0];
                    if (cellEl && headerPinLeft && razyui(cellEl).parent()[0] !== headerPinLeft) {
                        razyui(headerPinLeft).append(cellEl);
                    }
                    ctx.headerColumns[name].css('left', '').width(col.width);
                }
                ctx.poolCells.forEach(cells => { if (cells[name]) cells[name].width(col.width); });
            });
            // Pinned-right columns — move header cells to pin-right zone
            dirtyPinRight.forEach(name => {
                const col = ctx.gridColumn[name];
                if (!col) return;
                if (ctx.headerColumns[name]) {
                    const cellEl = ctx.headerColumns[name][0];
                    if (cellEl && headerPinRight && razyui(cellEl).parent()[0] !== headerPinRight) {
                        razyui(headerPinRight).append(cellEl);
                    }
                    ctx.headerColumns[name].css('left', '').width(col.width);
                }
                ctx.poolCells.forEach(cells => { if (cells[name]) cells[name].width(col.width); });
            });

            if (!nothingChanged) {
                reflowScrollableWidths(ctx);
                syncGroupZoneWidths(ctx);
                // Only do full group rebuild when not actively dragging (preserve transitions)
                if (!ctx.container.hasClass('is-column-dragging')) {
                    reflowGroupHeaders(ctx);
                }
                reflowFilterRow(ctx);
                updateSpacer(ctx);
            }
            updateScrollbarsDirect(ctx, _vpH, _scrollTop, fullVpW, _scrollLeft);
            ctx.observerLocked = false;
        });
    });
}


// ═════════════════════════════════════════════════════════════════
// reflowScrollableWidths — set row/data-zone widths
// ═════════════════════════════════════════════════════════════════

/**
 * Recompute scrollable column positions + widths across all zones.
 * Called during live resize for both column and group resize.
 * Avoids layout reads — uses cachedViewportWidth.
 * @param {Object} ctx
 */
export function reflowScrollableWidths(ctx) {
    const scrollable = getScrollableColumns(ctx);
    const cw = recomputeScrollablePositions(ctx, scrollable);
    const avail = Math.max(0, ctx.cachedViewportWidth - ctx.fixedLeftWidth - ctx.fixedRightWidth);
    const rowW = Math.max(cw, avail) + 'px';
    const contentW = cw + ctx.fixedLeftWidth + ctx.fixedRightWidth;
    const bodyW = contentW > ctx.cachedViewportWidth ? contentW + 'px' : '';

    // Header row — skip min-width when pin-right exists to avoid overflow
    if (!ctx.pinnedRight.length) {
        ctx.headerRow.css('min-width', rowW);
    } else {
        ctx.headerRow.css('min-width', '');
    }

    // Body rows — update each cell's left + width
    for (let i = 0; i < ctx.rowPool.length; i++) {
        razyui(ctx.rowPool[i]).css('width', bodyW);
        const cells = ctx.poolCells[i];
        if (cells) {
            for (const name of scrollable) {
                const cc = ctx.gridColumn[name];
                if (cc && cells[name]) cells[name].css('left', cc.position + 'px').width(cc.width);
            }
        }
    }

    // Filter row — update each filter cell's left + width
    if (ctx.filterRow) {
        ctx.filterRow.css('min-width', ctx.pinnedRight.length ? '' : rowW);
        for (const name of scrollable) {
            const fc = ctx.filterCells?.[name];
            if (fc?.[0]) {
                const cc = ctx.gridColumn[name];
                fc.css('left', (cc?.position || 0) + 'px').width(cc?.width || 0);
            }
        }
    }

    // Group headers
    if (ctx.columnGroups.length) {
        syncGroupZoneWidths(ctx);
        const groupRow = getGroupRow(ctx);
        if (groupRow?.[0]) groupRow.css('min-width', ctx.pinnedRight.length ? '' : rowW);
    }

    // Spacer width — drives horizontal scroll (rows are position:absolute)
    const spacer = ctx.rows.parent().find('.grid-table-spacer');
    if (spacer.length) spacer.css('width', bodyW);

    // Update pin-zone transform variables after content width change
    updatePinZoneTransforms(ctx, contentW);
}


// ═════════════════════════════════════════════════════════════════
// updatePinZoneTransforms — set CSS vars for pin-zone positioning
// ═════════════════════════════════════════════════════════════════

/**
 * Set --gt-scroll-x and --gt-scroll-x-right on the rows container
 * to position pin zones via CSS transforms (replaces position:sticky).
 * @param {Object} ctx
 * @param {number} [contentW] — total content width (optional, computed if omitted)
 */
export function updatePinZoneTransforms(ctx, contentW) {
    const rowsEl = ctx.rows?.[0];
    if (!rowsEl) return;
    const scrollLeft = ctx.scrollLeft || 0;
    if (contentW == null) {
        contentW = getScrollableColumnsWidth(ctx) + ctx.fixedLeftWidth + ctx.fixedRightWidth;
    }
    const vpW = ctx.cachedViewportWidth || 0;
    const maxScroll = Math.max(0, contentW - vpW);
    rowsEl.style.setProperty('--gt-scroll-x', scrollLeft + 'px');
    rowsEl.style.setProperty('--gt-scroll-x-right', (scrollLeft - maxScroll) + 'px');
}


// ═════════════════════════════════════════════════════════════════
// recomputeScrollablePositions
// ═════════════════════════════════════════════════════════════════

/**
 * Recalculate left-offset positions for scrollable columns.
 * Also updates header-cell DOM (left + width) for each scrollable column.
 * @param {Object} ctx
 * @param {string[]} scrollable — ordered scrollable column names
 * @returns {number} total scrollable columns width
 */
export function recomputeScrollablePositions(ctx, scrollable) {
    let pos = 0;
    for (const name of scrollable) {
        const cc = ctx.gridColumn[name];
        if (cc) {
            cc.position = pos;
            const h = ctx.headerColumns[name];
            if (h) h.css('left', pos + 'px').width(cc.width);
            pos += cc.width;
        }
    }
    return pos;
}


// ═════════════════════════════════════════════════════════════════
// syncGroupZoneWidths / reflowGroupHeaders
// ═════════════════════════════════════════════════════════════════

/**
 * Sync group header zone widths (currently handled by CSS variables).
 * @param {Object} ctx
 */
export function syncGroupZoneWidths(ctx) {
    const groupMap = getGroupIndexMap(ctx);
    const scrollable = getScrollableColumns(ctx);
    syncGroupCellWidths(ctx, getGroupRow(ctx)?.[0], scrollable, groupMap, true);
    const grpContainer = ctx.container.find('.grid-table-header-groups');
    syncGroupCellWidths(ctx, grpContainer.find('.grid-table-pin-left')[0], ctx.pinnedLeft, groupMap, false);
    syncGroupCellWidths(ctx, grpContainer.find('.grid-table-pin-right')[0], ctx.pinnedRight, groupMap, false);
}

/**
 * Walk group cells in a zone and update their widths (+ left for scrollable).
 * @param {Object} ctx
 * @param {Element} zoneEl
 * @param {string[]} columns
 * @param {Object} groupMap — plain object mapping column name → group index
 * @param {boolean} isScrollable
 */
function syncGroupCellWidths(ctx, zoneEl, columns, groupMap, isScrollable) {
    if (!zoneEl || !columns.length) return;
    // Build a lookup: data-group-idx → DOM element
    const cellByIdx = {};
    for (const child of zoneEl.children) {
        const gi = child.getAttribute('data-group-idx');
        if (gi != null) cellByIdx[gi] = child;
    }
    // Walk columns in order, compute each group's width (and left for scrollable)
    let pos = 0, accW = 0, prevGroup, prevGroupIdx;
    const flush = () => {
        if (prevGroupIdx == null) return;
        const cell = cellByIdx[prevGroupIdx];
        if (cell) {
            const $cell = razyui(cell);
            $cell.css('width', accW + 'px');
            if (isScrollable) $cell.css('left', (pos - accW) + 'px');
        }
    };
    for (const name of columns) {
        const gi = groupMap[name] ?? -1;
        const colW = ctx.gridColumn[name]?.width || 0;
        if (prevGroup !== undefined && gi !== prevGroup) {
            flush();
            accW = 0;
        }
        accW += colW;
        pos += colW;
        prevGroup = gi;
        prevGroupIdx = String(gi);
    }
    flush();
}

/**
 * Rebuild group header cells from scratch — clears all zones and rebuilds.
 * Called after column reorder, group block reorder, or pin changes.
 * @param {Object} ctx
 */
export function reflowGroupHeaders(ctx) {
    if (!ctx.columnGroups.length) return;
    // Invalidate lazy caches
    ctx.grpIdxMapCache = null;
    ctx.grpRowCache = undefined;
    const groupRow = ctx.container.find('.grid-table-header-groups > .grid-table-row');
    if (!groupRow[0]) return;
    groupRow.html('');
    // Also clear pinned group zones so stale cells don't linger
    const groupPinLeft = ctx.container.find('.grid-table-header-groups > .grid-table-pin-left');
    const groupPinRight = ctx.container.find('.grid-table-header-groups > .grid-table-pin-right');
    if (groupPinLeft[0]) groupPinLeft.html('');
    if (groupPinRight[0]) groupPinRight.html('');
    buildGroupHeaders(ctx, groupRow);
}


// ═════════════════════════════════════════════════════════════════
// reflowFilterRow
// ═════════════════════════════════════════════════════════════════

/**
 * Re-position and resize filter cells to match the current column layout.
 * @param {Object} ctx
 */
export function reflowFilterRow(ctx) {
    if (!ctx.showFilterRow || !ctx.filterRow) return;
    const scrollable = getScrollableColumns(ctx);

    // Resolve filter-row pin zones
    const filterParent = ctx.filterRow.parent()[0]; // .grid-table-filter-row
    const filterScrollRow = ctx.filterRow[0]; // .grid-table-row inside filter-row
    const filterPinLeft  = filterParent?.querySelector(':scope > .grid-table-pin-left');
    const filterPinRight = filterParent?.querySelector(':scope > .grid-table-pin-right');

    scrollable.forEach(name => {
        const col = ctx.gridColumn[name];
        const cell = ctx.filterCells[name];
        if (cell && col) {
            // Move back to scrollable zone if currently in a pin zone
            const cellEl = cell[0];
            if (cellEl && razyui(cellEl).parent()[0] !== filterScrollRow) {
                razyui(filterScrollRow).append(cellEl);
            }
            cell.css('left', col.position + 'px').width(col.width);
        }
    });
    // Pinned-left filter cells → move to pin-left zone
    ctx.pinnedLeft.forEach(name => {
        const col = ctx.gridColumn[name];
        const cell = ctx.filterCells[name];
        if (cell && col) {
            const cellEl = cell[0];
            if (cellEl && filterPinLeft && razyui(cellEl).parent()[0] !== filterPinLeft) {
                razyui(filterPinLeft).append(cellEl);
            }
            cell.css('left', '').width(col.width);
        }
    });
    // Pinned-right filter cells → move to pin-right zone
    ctx.pinnedRight.forEach(name => {
        const col = ctx.gridColumn[name];
        const cell = ctx.filterCells[name];
        if (cell && col) {
            const cellEl = cell[0];
            if (cellEl && filterPinRight && razyui(cellEl).parent()[0] !== filterPinRight) {
                razyui(filterPinRight).append(cellEl);
            }
            cell.css('left', '').width(col.width);
        }
    });
}


// ═════════════════════════════════════════════════════════════════
// updateVisibleRowLayout
// ═════════════════════════════════════════════════════════════════

/**
 * Update cell positions/widths for currently visible pool rows
 * after column changes.
 * @param {Object} ctx
 */
export function updateVisibleRowLayout(ctx) {
    const scrollable = getScrollableColumns(ctx);
    const scrollableW = getScrollableColumnsWidth(ctx);
    const contentW = scrollableW + ctx.fixedLeftWidth + ctx.fixedRightWidth;
    const vpW = getViewportWidth(ctx);
    ctx.rowPool.forEach(row => {
        const $row = razyui(row);
        $row.css('width', contentW > vpW ? contentW + 'px' : '');
        const $data = $row.find('.grid-table-data');
        if ($data.length) $data.css('width', scrollableW + 'px');
    });
    // Update cells
    ctx.poolCells.forEach(cells => {
        scrollable.forEach(name => {
            const col = ctx.gridColumn[name];
            if (cells[name]) cells[name].css('left', col.position + 'px').width(col.width);
        });
        [...ctx.pinnedLeft, ...ctx.pinnedRight].forEach(name => {
            const col = ctx.gridColumn[name];
            if (cells[name] && col) cells[name].width(col.width);
        });
    });
}


// ═════════════════════════════════════════════════════════════════
// applyColumnResize — live resize during drag
// ═════════════════════════════════════════════════════════════════

/**
 * Update a single column during drag resize — recompute positions,
 * update header/pool cells, sync scrollable widths and scrollbars.
 * @param {Object} ctx
 * @param {string} name — column name
 */
export function applyColumnResize(ctx) {
    const st = ctx.resizeState;
    if (!st) return;
    const delta = (st.lastX ?? st.startX) - st.startX;
    const name = st.name;
    const minW = ctx.columnConfig[name]?.minWidth || ctx.minColumnWidth;
    ctx.gridColumn[name].width = Math.max(minW, st.startWidth + delta);

    const isPinned = ctx.pinnedLeft.includes(name) || ctx.pinnedRight.includes(name);
    
    razyui.measure(() => {
        // Read scrollbar track width before mutating
        if (ctx.hscroll?.[0]) {
            ctx.hscrollTrackW = ctx.hscroll.prop('clientWidth');
            ctx.hscrollPadding = ctx.fixedLeftWidth + ctx.fixedRightWidth;
        }
        
        if (isPinned) {
            recalcFixedLeft(ctx);
            razyui.mutate(() => {
                resizePinnedColumn(ctx, name);
            });
        } else {
            razyui.mutate(() => {
                reflowScrollableWidths(ctx);
            });
        }
    });
}

/**
 * Update a single pinned column's header, body cells, and filter cell in-place.
 * @param {Object} ctx
 * @param {string} name — column name
 */
function resizePinnedColumn(ctx, name) {
    const w = ctx.gridColumn[name]?.width || 0;
    // Header
    const hc = ctx.headerColumns[name];
    if (hc) hc.width(w);
    // Body cells
    for (let i = 0; i < ctx.poolCells.length; i++) {
        const cell = ctx.poolCells[i]?.[name];
        if (cell) cell.width(w);
    }
    // Filter cell
    if (ctx.filterRow) {
        const fc = ctx.filterCells?.[name];
        if (fc?.[0]) fc.width(w);
    }
    // Group header widths (pin zone only)
    if (ctx.columnGroups.length) syncGroupZoneWidths(ctx);
}


// ═════════════════════════════════════════════════════════════════
// applyGroupResize — resize all columns in a group
// ═════════════════════════════════════════════════════════════════

/**
 * Apply group resize from rAF — scales all scrollable columns in the group proportionally.
 * Reads from ctx.groupResizeState.
 * @param {Object} ctx
 */
export function applyGroupResize(ctx) {
    const st = ctx.groupResizeState;
    if (!st) return;
    const delta = (st.lastX ?? st.startX) - st.startX;
    const newTotalW = Math.max(st.columns.length * ctx.minColumnWidth, st.startTotalWidth + delta);
    const scale = newTotalW / st.startTotalWidth;
    for (const c of st.columns) {
        const minW = ctx.columnConfig[c]?.minWidth || ctx.minColumnWidth;
        ctx.gridColumn[c].width = Math.max(minW, Math.round(st.startWidths[c] * scale));
    }
    
    razyui.measure(() => {
        if (ctx.hscroll?.[0]) {
            ctx.hscrollTrackW = ctx.hscroll.prop('clientWidth');
            ctx.hscrollPadding = ctx.fixedLeftWidth + ctx.fixedRightWidth;
        }
        razyui.mutate(() => {
            reflowScrollableWidths(ctx);
        });
    });
}


// ═════════════════════════════════════════════════════════════════
// autoSizeColumns / autoFitColumn
// ═════════════════════════════════════════════════════════════════

/**
 * Auto-size columns: auto-fit marked columns, then distribute remaining
 * viewport space via grow factors.
 * @param {Object} ctx
 */
export function autoSizeColumns(ctx) {
    razyui.measure(() => {
        if (!ctx.rows?.[0]?.firstElementChild) return;
        ctx.observerLocked = true;

        const scrollable = getScrollableColumns(ctx);
        const vpW = getDataAreaWidth(ctx);
        const _vp = ctx.viewport?.[0];
        const _scrollTop = _vp ? _vp.scrollTop : 0;
        const _scrollLeft = ctx.scrollLeft;
        const _vpH = _vp ? _vp.clientHeight : 0;
        const _vpW = _vp ? _vp.clientWidth : 0;
        updateHScrollbarCached(ctx);

        // Auto-fit columns marked with autoFit
        const autoFitNames = [];
        scrollable.forEach(name => {
            if (ctx.columnConfig[name].autoFit) autoFitNames.push(name);
        });
        [...ctx.pinnedLeft, ...ctx.pinnedRight].forEach(name => {
            if (ctx.columnConfig[name].autoFit) autoFitNames.push(name);
        });
        if (autoFitNames.length > 0) {
            autoFitColumns(ctx, autoFitNames);
        }

        // Distribute remaining space via grow factors
        let scrollableW = scrollable.reduce((s, n) => s + (ctx.gridColumn[n]?.width || 0), 0);
        const extra = vpW - scrollableW;
        if (extra > 0) {
            const growTotal = scrollable.reduce((s, n) => s + (ctx.columnConfig[n]?.grow || 0), 0);
            if (growTotal > 0) {
                scrollable.forEach(name => {
                    const grow = ctx.columnConfig[name]?.grow || 0;
                    if (grow > 0) ctx.gridColumn[name].width += (grow / growTotal) * extra;
                });
            } else {
                // No grow — distribute evenly
                const perCol = extra / scrollable.length;
                scrollable.forEach(name => { ctx.gridColumn[name].width += perCol; });
            }
        }

        // Recompute positions
        let left = 0;
        scrollable.forEach(name => {
            ctx.gridColumn[name].position = left;
            left += ctx.gridColumn[name].width;
        });

        recalcFixedLeft(ctx);

        // Apply widths
        razyui.mutate(() => {
            const headerParent = ctx.headerRow.parent()[0];
            const headerPinLeft  = headerParent?.querySelector(':scope > .grid-table-pin-left');
            const headerPinRight = headerParent?.querySelector(':scope > .grid-table-pin-right');

            scrollable.forEach(name => {
                const col = ctx.gridColumn[name];
                if (ctx.headerColumns[name]) {
                    const cellEl = ctx.headerColumns[name][0];
                    if (cellEl && razyui(cellEl).parent()[0] !== ctx.headerRow[0]) {
                        ctx.headerRow.append(cellEl);
                    }
                    ctx.headerColumns[name].css('left', col.position + 'px').width(col.width);
                }
                ctx.poolCells.forEach(cells => {
                    if (cells[name]) cells[name].css('left', col.position + 'px').width(col.width);
                });
            });
            ctx.pinnedLeft.forEach(name => {
                const col = ctx.gridColumn[name];
                if (!col) return;
                if (ctx.headerColumns[name]) {
                    const cellEl = ctx.headerColumns[name][0];
                    if (cellEl && headerPinLeft && razyui(cellEl).parent()[0] !== headerPinLeft) {
                        razyui(headerPinLeft).append(cellEl);
                    }
                    ctx.headerColumns[name].css('left', '').width(col.width);
                }
                ctx.poolCells.forEach(cells => { if (cells[name]) cells[name].width(col.width); });
            });
            ctx.pinnedRight.forEach(name => {
                const col = ctx.gridColumn[name];
                if (!col) return;
                if (ctx.headerColumns[name]) {
                    const cellEl = ctx.headerColumns[name][0];
                    if (cellEl && headerPinRight && razyui(cellEl).parent()[0] !== headerPinRight) {
                        razyui(headerPinRight).append(cellEl);
                    }
                    ctx.headerColumns[name].css('left', '').width(col.width);
                }
                ctx.poolCells.forEach(cells => { if (cells[name]) cells[name].width(col.width); });
            });

            reflowScrollableWidths(ctx);
            syncGroupZoneWidths(ctx);
            // Only do full group rebuild when not actively dragging (preserve transitions)
            if (!ctx.container.hasClass('is-column-dragging')) {
                reflowGroupHeaders(ctx);
            }
            reflowFilterRow(ctx);
            updateSpacer(ctx);
            updateScrollbarsDirect(ctx, _vpH, _scrollTop, _vpW, _scrollLeft);
            ctx.observerLocked = false;
        });
    });
}

/**
 * Measure the max content width of multiple columns across header +
 * visible pool cells and apply it.
 *
 * Uses an off-screen measurement element to avoid triggering synchronous
 * reflow on visible cells. For each column, clone the header + first few
 * visible cells into a hidden container, set `width: max-content`, and
 * read the intrinsic width once, then remove the clones.
 *
 * Falls back to the direct measurement approach when the off-screen
 * container cannot be created (e.g. during initial build before DOM is
 * attached).
 *
 * @param {Object} ctx
 * @param {string[]} names — column names
 */
export function autoFitColumns(ctx, names) {
    const maxWMap = {};

    // Collect all cells to measure
    const allCells = [];
    const prevWidths = [];
    names.forEach(name => {
        const cc = ctx.columnConfig[name];
        const minW = cc.minWidth || ctx.minColumnWidth;
        maxWMap[name] = minW;

        const hdr = ctx.headerColumns[name]?.[0];
        if (hdr) allCells.push({ name, cell: hdr });
        // Only measure a limited sample of pool cells (first 8) to reduce reflow cost
        let sampled = 0;
        for (const cells of ctx.poolCells) {
            if (sampled >= 8) break;
            const cell = cells[name]?.[0];
            if (cell) {
                allCells.push({ name, cell });
                sampled++;
            }
        }
    });

    // Phase 1 — set all widths to max-content (batched writes, no reflow)
    allCells.forEach(item => {
        const $cell = razyui(item.cell);
        const w = $cell.css('width');
        $cell.css('width', 'max-content');
        prevWidths.push(w);
    });

    // Phase 2 — read natural widths (one synchronous reflow)
    allCells.forEach(item => {
        maxWMap[item.name] = Math.max(maxWMap[item.name], item.cell.offsetWidth);
    });

    // Phase 3 — restore original widths
    allCells.forEach((item, i) => {
        razyui(item.cell).css('width', prevWidths[i]);
    });

    // Apply max widths
    names.forEach(name => {
        ctx.gridColumn[name].width = maxWMap[name];
    });
}

export function autoFitColumn(ctx, name) {
    autoFitColumns(ctx, [name]);
}


// ═════════════════════════════════════════════════════════════════
// saveDefaultColumnWidths — snapshot widths after initial auto-size
// ═════════════════════════════════════════════════════════════════

/**
 * Save current column widths + grow factors as restore-able defaults.
 * Called once after the first auto-size pass completes.
 * @param {Object} ctx
 */
export function saveDefaultColumnWidths(ctx) {
    ctx.defaultColumnWidths = {};
    ctx.defaultColumnGrow = {};
    ctx.columnOrder.forEach(name => {
        ctx.defaultColumnWidths[name] = ctx.gridColumn[name]?.width || 0;
        ctx.defaultColumnGrow[name] = ctx.columnConfig[name]?.grow || 0;
    });
    [...ctx.pinnedLeft, ...ctx.pinnedRight].forEach(name => {
        if (!ctx.defaultColumnWidths[name]) {
            ctx.defaultColumnWidths[name] = ctx.gridColumn[name]?.width || 0;
            ctx.defaultColumnGrow[name] = ctx.columnConfig[name]?.grow || 0;
        }
    });
}

/**
 * Restore column widths + grow factors from the saved defaults.
 * @param {Object} ctx
 */
export function restoreDefaultColumnWidths(ctx) {
    if (!ctx.defaultColumnWidths) return;
    ctx.columnOrder.forEach(name => {
        if (ctx.defaultColumnWidths[name] != null) {
            ctx.gridColumn[name].width = ctx.defaultColumnWidths[name];
        }
        if (ctx.defaultColumnGrow[name] != null) {
            ctx.columnConfig[name].grow = ctx.defaultColumnGrow[name];
        }
    });
    [...ctx.pinnedLeft, ...ctx.pinnedRight].forEach(name => {
        if (ctx.defaultColumnWidths[name] != null) {
            ctx.gridColumn[name].width = ctx.defaultColumnWidths[name];
        }
        if (ctx.defaultColumnGrow[name] != null) {
            ctx.columnConfig[name].grow = ctx.defaultColumnGrow[name];
        }
    });
}


// ═════════════════════════════════════════════════════════════════
// reflowAfterResize — lightweight reflow after single-column resize
// ═════════════════════════════════════════════════════════════════

/**
 * Reflow positions, scrollbars, group headers, and filter row after
 * a single-column resize — does NOT redistribute grow/shrink among
 * other columns.
 * @param {Object} ctx
 */
export function reflowAfterResize(ctx) {
    recalcFixedLeft(ctx);
    reflowScrollableWidths(ctx);
    syncGroupZoneWidths(ctx);
    if (!ctx.container.hasClass('is-column-dragging')) {
        reflowGroupHeaders(ctx);
    }
    reflowFilterRow(ctx);
    updateSpacer(ctx);
    updateHScrollbarCached(ctx);
    updateScrollbars(ctx);
}


// ═════════════════════════════════════════════════════════════════
// updateSpacer — virtual scroll height + width placeholder
// ═════════════════════════════════════════════════════════════════

/**
 * Maintain the spacer div dimensions for virtual scroll layout.
 * Height drives vertical scroll; width drives horizontal scroll
 * (rows are position:absolute so they don't contribute to scrollWidth).
 * @param {Object} ctx
 */
export function updateSpacer(ctx) {
    const total = getDisplayCount(ctx);
    const totalH = ctx.rowOffsets[total] || 0;
    const rowsParent = ctx.rows.parent();
    if (rowsParent.length) {
        let spacer = rowsParent.find('.grid-table-spacer')[0];
        if (!spacer) {
            const sp = razyui.el('div', { className: 'grid-table-spacer' });
            rowsParent.append(sp[0]);
            spacer = sp[0];
        }
        const contentW = getScrollableColumnsWidth(ctx) + ctx.fixedLeftWidth + ctx.fixedRightWidth;
        const vpW = ctx.cachedViewportWidth || 0;
        const $spacer = razyui(spacer);
        $spacer.css('height', ctx.enableVscroll ? totalH + 'px' : '0');
        $spacer.css('width', contentW > vpW ? contentW + 'px' : '');
    }
}


// ═════════════════════════════════════════════════════════════════
// Scrollbar management
// ═════════════════════════════════════════════════════════════════

/**
 * Cache H-scrollbar track width and padding.
 * @param {Object} ctx
 */
export function updateHScrollbarCached(ctx) {
    if (!ctx.hscroll?.[0]) return;
    const track = ctx.hscroll[0];
    ctx.hscrollTrackW = track.clientWidth;
    ctx.hscrollPadding = ctx.fixedLeftWidth + ctx.fixedRightWidth;
}

/**
 * Compute and position vertical & horizontal scrollbar thumbs.
 * @param {Object} ctx
 */
export function updateScrollbars(ctx) {
    if (!ctx.viewport?.[0]) return;
    
    razyui.measure(() => {
        const vp = ctx.viewport[0];
        const vpH = vp.clientHeight;
        const scrollTop = vp.scrollTop;
        const scrollLeft = ctx.scrollLeft;
        
        updateHScrollbarCached(ctx);
        
        razyui.mutate(() => {
            updateScrollbarsDirect(ctx, vpH, scrollTop, vp.clientWidth, scrollLeft);
        });
    });
}

/**
 * Position scrollbar thumbs using pre-read values (no DOM reads).
 * Call from inside a mutate/write phase.
 * @param {Object} ctx
 * @param {number} vpH   – viewport clientHeight
 * @param {number} scrollTop
 * @param {number} vpW   – viewport clientWidth
 * @param {number} scrollLeft
 */
export function updateScrollbarsDirect(ctx, vpH, scrollTop, vpW, scrollLeft) {
    const totalH = ctx.rowOffsets[getDisplayCount(ctx)] || 0;
    const contentW = getScrollableColumnsWidth(ctx);
    const dataW = Math.max(0, vpW - ctx.fixedLeftWidth - ctx.fixedRightWidth);

    // Vertical scrollbar
    if (totalH <= vpH) {
        ctx.vthumb.css('display', 'none');
    } else {
        ctx.vthumb.css('display', '');
        const thumbH = Math.max(24, (vpH / totalH) * vpH);
        ctx.vthumb.height(thumbH);
        const ratio = scrollTop / (totalH - vpH);
        ctx.vthumb.css('top', (ratio * (vpH - thumbH)) + 'px');
    }

    // Horizontal scrollbar
    if (contentW <= dataW || dataW <= 0) {
        ctx.hthumb.css('display', 'none');
    } else {
        ctx.hthumb.css('display', '');
        const trackW = ctx.hscrollTrackW;
        const pad = ctx.hscrollPadding;
        const usable = trackW - pad;
        const thumbW = Math.max(24, (dataW / contentW) * usable);
        ctx.hthumb.width(thumbW);
        const maxScroll = contentW - dataW;
        const ratio = maxScroll > 0 ? scrollLeft / maxScroll : 0;
        ctx.hthumb.css('left', (ctx.fixedLeftWidth + ratio * (usable - thumbW)) + 'px');
    }
}

/**
 * Adjust pinned-right zone offset when vertical scrollbar is visible.
 * @param {Object} ctx
 */
export function updatePinRightShift(ctx) {
    // No-op: --pr-shift is not consumed by any CSS rule.
    // Pin-right columns use position:sticky; right:0 instead.
}
