/**
 * @fileoverview GridTable view — DOM construction for the container shell,
 *               header cells, group headers, filter row, side panel,
 *               row elements, pagination footer, and column context menu.
 *
 * Every exported function receives the thin `ctx` context object produced
 * by the class's `#ctx()` bridge (see index.js).
 *
 * @module module/GridTable/view
 */

import razyui from '../../index.js';
import Icons from '../Icons.js';
import { MAX_PAGE_BUTTONS, PART } from './constants.js';
import { collectColumnOptions, detectFilterType, getNestedValue } from './helpers.js';
import { setContent } from '../shared/setContent.js';

// ═══════════════════════════════════════════════
// Container spell string
// ═══════════════════════════════════════════════

/**
 * Build the razyui-spell string for the entire GridTable container tree.
 * @param {Object} flags
 * @returns {string}
 */
export function buildContainerSpell({ hasToolbar, hasToolside, showCheckbox, showFilterRow, showSidePanel, hasColumnGroups }) {
    const sp = ['div.[grid-table]-container('];
    if (hasToolbar) sp.push('div.$-toolbar,');
    sp.push('div.[$]-main(');
    sp.push('div.[$]-wrapper(');

    const leftZone = () => {
        let z = '';
        if (hasToolside) z += 'div.$-toolside,';
        z += 'div.$-pin-left,';
        if (showCheckbox) z += 'div.$-checkbox-col,';
        return z;
    };

    sp.push('div.[$]-header(');
    if (hasColumnGroups) {
        sp.push('div.[$]-header-groups(' + leftZone() + 'div.$-row,div.$-pin-right),');
    }
    sp.push('div.[$]-header-columns(' + leftZone() + 'div.$-row,div.$-pin-right)');
    if (showFilterRow) {
        sp.push(',div.[$]-filter-row(' + leftZone() + 'div.$-row,div.$-pin-right)');
    }
    sp.push('),'); // close header

    sp.push('div.[$]-body(');
    sp.push('div.[$]-viewport(div.$-spacer,div.$-rows),');
    sp.push('div.$-empty-message,');
    sp.push('div.[$]-hscroll(div.$-hthumb),');
    sp.push('div.[$]-vscroll(div.$-vthumb))');
    sp.push(')'); // close wrapper

    if (showSidePanel) {
        sp.push(',div.$-panel-bar');
        sp.push(',div.[$]-side-panel(');
        sp.push('div.[$]-panel-header(span.$-panel-title,button.$-panel-close)');
        sp.push(',div.[$]-panel-search(input)');
        sp.push(',div.[$]-panel-body(');
        sp.push('div.$-panel-columns,');
        sp.push('div.$-panel-filters))');
    }

    sp.push(')'); // close main
    sp.push(',div.$-footer');
    sp.push(',div.$-drag-ghost');
    sp.push(',div.$-row-drag-ghost');
    sp.push(')'); // close container

    return sp.join('');
}

/**
 * Collect main DOM element references from the container.
 * @param {Object} container — razyui-wrapped container element
 * @returns {Object}
 */
export function collectDOMRefs(container) {
    return container.collect({
        wrapper: '.grid-table-wrapper',
        header: '.grid-table-header',
        viewport: '.grid-table-viewport',
        rows: '.grid-table-rows',
        spacer: '.grid-table-spacer',
        emptyMsg: '.grid-table-empty-message',
        vscroll: '.grid-table-vscroll',
        hscroll: '.grid-table-hscroll',
        vthumb: '.grid-table-vthumb',
        hthumb: '.grid-table-hthumb',
        footer: '.grid-table-footer',
        colDragGhost: '.grid-table-drag-ghost',
        rowDragGhost: '.grid-table-row-drag-ghost',
    }, 0);
}

// ═══════════════════════════════════════════════
// Header
// ═══════════════════════════════════════════════

/**
 * Build multi-level group headers + data column header row.
 * @param {Object} ctx
 */
export function buildHeader(ctx) {
    const razyui = ctx.razyui;
    const headerRow = ctx.container.find('.grid-table-header-columns > .grid-table-row');
    ctx.headerRow = headerRow;

    // Toolside header
    const hasToolside = ctx.showDragHandle || ctx.showRowNumbers || !!ctx.subRowFn;
    if (hasToolside) {
        const toolside = ctx.container.find('.grid-table-header-columns > .grid-table-toolside');
        if (ctx.showDragHandle) {
            toolside.append(razyui.spell('div.grid-table-cell.is-drag-handle', true));
        }
        if (ctx.showRowNumbers) {
            toolside.append(razyui.spell('div.grid-table-cell.is-row-number', true).html('#'));
        }
        if (ctx.subRowFn) {
            toolside.append(razyui.spell('div.grid-table-cell.is-expand-placeholder', true));
        }
    }

    // Checkbox header
    if (ctx.showCheckbox) {
        const checkZone = ctx.container.find('.grid-table-header-columns > .grid-table-checkbox-col');
        const checkAll = razyui.spell('input', true);
        checkAll.attr('type', 'checkbox');
        checkAll.on('change', () => ctx.toggleSelectAll());
        checkZone.append(checkAll);
    }

    // Multi-level group headers
    if (ctx.columnGroups.length) {
        buildGroupHeaders(ctx, ctx.container.find('.grid-table-header-groups > .grid-table-row'));
    }

    // Data column headers
    let position = 0;
    ctx.columnOrder.forEach((name) => {
        const cell = razyui.spell('div.grid-table-cell', true);
        cell.attr('data-name', name).css('left', position + 'px');

        const label = razyui.spell('span.grid-table-label', true).text(ctx.labels[name] || name);
        PART.LABEL.apply(label);
        const sortIcon = razyui.spell('span.grid-table-sort-icon', true);
        PART.SORT_ICON.apply(sortIcon);
        sortIcon.html(Icons.svg('sort-both', { size: 12, strokeWidth: 2 }));
        if (ctx.columnConfig[name]?.component || ctx.columnConfig[name]?.printHTML) sortIcon.css('display', 'none');
        const menuIcon = razyui.spell('span.grid-table-menu-icon', true).html(Icons.svg('more-vertical', { size: 14, strokeWidth: 1.8 }));
        PART.MENU_ICON.apply(menuIcon);
        const resizer = razyui.spell('div.grid-table-resizer', true);
        PART.RESIZER.apply(resizer);
        cell.append(label).append(sortIcon).append(menuIcon).append(resizer);

        headerRow.append(cell);
        ctx.headerColumns[name] = cell;

        const measuredWidth = Math.ceil(cell.prop('scrollWidth') || 0);
        const presetWidth = ctx.columnConfig[name]?.width || 0;
        const minWidth = Math.max(ctx.columnConfig[name]?.minWidth || ctx.minColumnWidth, measuredWidth);

        ctx.gridColumn[name] = {
            position,
            width: Math.max(minWidth, presetWidth || measuredWidth),
            headerWidth: measuredWidth,
        };
        cell.width(ctx.gridColumn[name].width);
        position += ctx.gridColumn[name].width;

        ctx.resizeScope.observe(cell[0], ctx.resizeCb);
    });

    ctx.reflowColumns();
}

/**
 * Build group header cells that span multiple columns.
 * @param {Object} ctx
 * @param {Object} groupRow — razyui-wrapped scrollable group-row element
 */
export function buildGroupHeaders(ctx, groupRow) {
    const razyui = ctx.razyui;
    const groupMap = new Map();
    ctx.columnGroups.forEach((g, gi) => {
        (g.columns || []).forEach(col => groupMap.set(col, { group: g, idx: gi }));
    });

    const pinSet = new Set(ctx.pinnedLeft);
    const groupPinZone = ctx.container.find('.grid-table-header-groups > .grid-table-pin-left');

    // Pinned-left group cells
    if (groupPinZone[0] && ctx.pinnedLeft.length) {
        groupPinZone.html('');
        let currentGroup = null, groupCell = null, groupStart = 0, pinPos = 0;
        ctx.pinnedLeft.forEach((name) => {
            const info = groupMap.get(name) || null;
            const group = info?.group || null;
            const colWidth = ctx.gridColumn[name]?.width || 0;
            if (group !== currentGroup) {
                if (groupCell) groupCell.width(pinPos - groupStart);
                currentGroup = group;
                groupStart = pinPos;
                groupCell = razyui.spell('div.grid-table-group-cell', true);
                PART.GROUP_CELL.apply(groupCell);
                groupCell.text(group ? group.label : '');
                if (!group) {
                    groupCell.css('visibility', 'hidden');
                    groupCell.attr('data-group-idx', '-1');
                } else {
                    groupCell.attr('data-group-idx', String(info.idx));
                }
                groupPinZone.append(groupCell);
            }
            pinPos += colWidth;
        });
        if (groupCell) groupCell.width(pinPos - groupStart);
    }

    // Scrollable group cells
    let position = 0, currentGroup = null, groupCell = null, groupStart = 0;
    const scrollable = ctx.getScrollableColumns();

    scrollable.forEach((name) => {
        const info = groupMap.get(name) || null;
        const group = info?.group || null;
        const colWidth = ctx.gridColumn[name]?.width || 0;

        if (group !== currentGroup) {
            if (groupCell) groupCell.width(position - groupStart);
            currentGroup = group;
            groupStart = position;
            groupCell = razyui.spell('div.grid-table-group-cell', true);
            PART.GROUP_CELL.apply(groupCell);
            groupCell.css('left', position + 'px')
                     .text(group ? group.label : '');
            if (!group) {
                groupCell.css('visibility', 'hidden');
                groupCell.attr('data-group-idx', '-1');
            } else {
                groupCell.attr('data-group-idx', String(info.idx));
                const grpResizer = razyui.spell('div.grid-table-resizer', true);
                PART.RESIZER.apply(grpResizer);
                groupCell.css('cursor', 'grab')
                         .append(grpResizer);
            }
            groupRow.append(groupCell);
        }
        position += colWidth;
    });
    if (groupCell) groupCell.width(position - groupStart);

    // Pinned-right group cells
    const groupPinRightZone = ctx.container.find('.grid-table-header-groups > .grid-table-pin-right');
    if (groupPinRightZone[0] && ctx.pinnedRight.length) {
        groupPinRightZone.html('');
        let cg = null, gc = null, gs = 0, pp = 0;
        ctx.pinnedRight.forEach((name) => {
            const info = groupMap.get(name) || null;
            const group = info?.group || null;
            const colWidth = ctx.gridColumn[name]?.width || 0;
            if (group !== cg) {
                if (gc) gc.width(pp - gs);
                cg = group; gs = pp;
                gc = razyui.spell('div.grid-table-group-cell', true);
                PART.GROUP_CELL.apply(gc);
                gc.text(group ? group.label : '');
                if (!group) { gc.css('visibility', 'hidden'); gc.attr('data-group-idx', '-1'); }
                else gc.attr('data-group-idx', String(info.idx));
                groupPinRightZone.append(gc);
            }
            pp += colWidth;
        });
        if (gc) gc.width(pp - gs);
    }
}

// ═══════════════════════════════════════════════
// Filter row
// ═══════════════════════════════════════════════

/**
 * Build the filter row with one cell per visible column.
 * @param {Object} ctx
 */
export function buildFilterRow(ctx) {
    const filterRow = ctx.container.find('.grid-table-filter-row > .grid-table-row');
    ctx.filterRow = filterRow;

    ctx.columnOrder.forEach((name) => {
        const colCfg = ctx.columnConfig[name] || {};
        const filterType = colCfg.filter || 'auto';
        const effective = filterType === 'auto' ? 'text' : filterType;
        const cell = buildFilterCell(ctx, name, effective);
        ctx.filterCells[name] = cell;
        filterRow.append(cell);
    });
}

/**
 * Build a single filter cell DOM element for the given column and filter type.
 * @param {Object} ctx
 * @param {string} name — column name
 * @param {string} filterType — 'text' | 'select' | 'group' | 'date'
 * @returns {Object} razyui-wrapped cell element
 */
export function buildFilterCell(ctx, name, filterType) {
    const razyui = ctx.razyui;
    const cell = razyui.spell('div.grid-table-filter-cell', true);
    PART.FILTER_CELL.apply(cell);
    cell.attr({ 'data-name': name, 'data-filter': filterType });

    if (filterType === 'select' || filterType === 'group') {
        // ── Combobox-based group filter ──
        const selectEl = razyui.el('select', { multiple: true });
        cell.append(selectEl);
        ctx.filterComponents[name] = { type: filterType, instance: null };

        if (filterType === 'select') {
            const inp = razyui.el('input', { type: 'text', placeholder: '' });
            cell[0].insertBefore(inp[0], selectEl[0]);
        }

        razyui.load('Combobox').then((Combobox) => {
            const options = collectColumnOptions(ctx.data, name);
            const sb = new Combobox(selectEl[0], {
                placeholder: '\u25BE Filter',
                renderContext: 'grid-filter',
                onSelect: (selected) => {
                    if (!selected || (Array.isArray(selected) && selected.length === 0)) {
                        ctx.filterGroupValues[name] = null;
                    } else {
                        ctx.filterGroupValues[name] = new Set(Array.isArray(selected) ? selected : [selected]);
                    }
                    ctx.applyFilters();
                },
            });
            sb.setOptions(options);
            ctx.filterComponents[name].instance = sb;
        });
    } else if (filterType === 'date') {
        // ── DatePicker-based date range filter ──
        const inp = razyui.el('input', { type: 'text', readOnly: true, placeholder: 'Date range...' });
        cell.append(inp);
        ctx.filterComponents[name] = { type: 'date', instance: null };

        const resetBtn = razyui.el('span', { className: 'grid-table-filter-reset', innerHTML: Icons.svg('xmark', { size: 12, strokeWidth: 2 }), title: 'Clear date filter' });
        PART.FILTER_RESET.apply(resetBtn);
        cell.append(resetBtn);

        razyui.load('DatePicker').then((DatePicker) => {
            const dp = new DatePicker(inp[0], {
                type: 'date',
                mode: 'range',
                placeholder: 'Date range...',
                renderContext: 'grid-filter',
                onChange: (value) => {
                    if (!value) {
                        ctx.filterValues[name] = '';
                    } else {
                        const parts = String(value).split('~').map(s => s.trim());
                        ctx.filterValues[name] = {
                            from: parts[0] || null,
                            to: parts[1] || parts[0] || null,
                        };
                    }
                    ctx.applyFilters();
                },
            });
            ctx.filterComponents[name].instance = dp;
        });
    } else {
        // ── Default text filter ──
        const inp = razyui.el('input', { type: 'text', placeholder: '' });
        cell.append(inp);
        const icon = razyui.spell('span.grid-table-filter-icon', true).html(Icons.svg('filter', { size: 12, strokeWidth: 1.5 }));
        PART.FILTER_ICON.apply(icon);
        cell.append(icon);
        ctx.filterComponents[name] = { type: 'text' };
    }

    return cell;
}

/**
 * Auto-detect filter types for columns configured as 'auto' and rebuild
 * their filter cells.
 * @param {Object} ctx
 */
export function autoDetectFilters(ctx) {
    if (!ctx.showFilterRow || !ctx.filterRow) return;

    ctx.columnOrder.forEach((name) => {
        const colCfg = ctx.columnConfig[name] || {};
        if (colCfg.filter !== 'auto') return;

        const detected = detectFilterType(ctx.data, name);
        const existing = ctx.filterComponents[name];
        if (existing && existing.type === detected) return;

        // Destroy existing component if present
        if (existing && existing.instance && typeof existing.instance.destroy === 'function') {
            existing.instance.destroy();
        }

        delete ctx.filterValues[name];
        delete ctx.filterGroupValues[name];

        const oldCell = ctx.filterCells[name];
        const newCell = buildFilterCell(ctx, name, detected);
        ctx.filterCells[name] = newCell;

        if (oldCell && oldCell[0]) {
            const w = oldCell[0].style.width || oldCell[0].style.minWidth;
            if (w) newCell.css('width', w);
            oldCell[0].replaceWith(newCell[0]);
        }
    });
}

/**
 * Refresh Combobox options for group/select filter columns when data changes.
 * @param {Object} ctx
 */
export function refreshFilterOptions(ctx) {
    if (!ctx.showFilterRow) return;
    for (const name of ctx.columnOrder) {
        const comp = ctx.filterComponents[name];
        if (!comp || !comp.instance) continue;
        if (comp.type === 'group' || comp.type === 'select') {
            const options = collectColumnOptions(ctx.data, name);
            comp.instance.setOptions(options);
        }
    }
}

// ═══════════════════════════════════════════════
// Side panel
// ═══════════════════════════════════════════════

/**
 * Build the side panel (overlays on right, with vertical tab bar).
 * @param {Object} ctx
 */
export function buildSidePanel(ctx) {
    const razyui = ctx.razyui;
    ctx.sidePanel = ctx.container.find('.grid-table-side-panel');
    ctx.sidePanel.addClass('is-collapsed');

    const panelBar = ctx.container.find('.grid-table-panel-bar');
    ctx.panelBar = panelBar;

    // Title header with close button
    const closeBtn = ctx.container.find('.grid-table-panel-close');
    closeBtn.html(Icons.svg('xmark', { size: 14, strokeWidth: 2 })).on('click', () => ctx.closePanel());

    // Search input
    const searchInput = ctx.container.find('.grid-table-panel-search input');
    searchInput.attr({ type: 'text', placeholder: 'Search...' });

    // Column list with checkboxes
    const columnsPanel = ctx.container.find('.grid-table-panel-columns');
    const columnList = razyui.spell('div.grid-table-column-list', true);
    PART.COLUMN_LIST.apply(columnList);
    const dropIndicator = razyui.spell('div.grid-table-column-drop-indicator', true);
    PART.COLUMN_DROP_IND.apply(dropIndicator);
    columnList.append(dropIndicator);
    buildColumnList(ctx, columnList);
    columnsPanel.append(columnList);

    // Search filter for column list
    searchInput.on('input', (e) => {
        const kw = e.target.value.toLowerCase();
        columnList.find('.grid-table-column-item').each((el) => {
            const name = el.getAttribute('data-name');
            const label = (ctx.labels[name] || name).toLowerCase();
            razyui(el).css('display', label.includes(kw) ? '' : 'none');
        });
    });

    // Bar buttons
    const colBtn = razyui.spell('div.grid-table-bar-btn', true);
    PART.BAR_BTN.apply(colBtn);
    colBtn.attr('name', 'columns').html(Icons.svg('layout', { size: 14, strokeWidth: 1.5 })).attr('title', 'Columns');
    const filterBtn = razyui.spell('div.grid-table-bar-btn', true);
    PART.BAR_BTN.apply(filterBtn);
    filterBtn.attr('name', 'filters').html(Icons.svg('filter', { size: 14, strokeWidth: 1.5 })).attr('title', 'Filters');
    panelBar.append(colBtn).append(filterBtn);

    // Register built-in sections
    ctx.panelSections.columns = {
        title: 'Columns',
        barBtn: colBtn[0],
        bodyEl: columnsPanel[0],
    };
    ctx.panelSections.filters = {
        title: 'Filters',
        barBtn: filterBtn[0],
        bodyEl: ctx.container.find('.grid-table-panel-filters')[0],
    };

    // Bar button click → toggle panel to that section
    panelBar.on('click', (e) => {
        const el = razyui(e.target).closest('.grid-table-bar-btn', panelBar);
        if (!el.length) return;
        const name = el.attr('name');
        if (!name) return;
        ctx.openPanel(name);
    });
}

/**
 * Activate a panel section by name, showing its content and updating the title.
 * @param {Object} ctx
 * @param {string} name
 */
export function activatePanel(ctx, name) {
    if (!ctx.sidePanel) return;
    const section = ctx.panelSections[name];
    if (!section) return;

    const razyui = ctx.razyui;
    const titleEl = ctx.sidePanel.find('.grid-table-panel-title');
    if (titleEl[0]) titleEl.text(section.title);

    const body = ctx.sidePanel.find('.grid-table-panel-body');
    body.children().each(c => { razyui(c).css('display', 'none'); });
    if (section.bodyEl) razyui(section.bodyEl).css('display', '');

    const searchBox = ctx.sidePanel.find('.grid-table-panel-search');
    if (searchBox[0]) searchBox.css('display', name === 'columns' ? '' : 'none');

    if (ctx.panelBar) {
        ctx.panelBar.find('.grid-table-bar-btn').each(b => {
            razyui(b).removeClass('is-active');
        });
        const btn = ctx.panelBar.find(`[name="${name}"]`);
        if (btn[0]) btn.addClass('is-active');
    }
}

/**
 * Build column visibility tree for the side panel.
 * @param {Object} ctx
 * @param {Object} columnList — razyui-wrapped container element
 */
export function buildColumnList(ctx, columnList) {
    const razyui = ctx.razyui;

    const buildItem = (name, indent = 0, groupName = null) => {
        const label = ctx.labels[name] || name;
        const item = razyui.spell('div.grid-table-column-item(span.grid-table-column-grip,input,span)', true);
        PART.COLUMN_ITEM.apply(item);
        item.attr('data-name', name);
        if (groupName != null) item.attr('data-group', groupName);
        if (indent) item.css('padding-left', (indent * 16 + 8) + 'px');

        const grip = item.find('.grid-table-column-grip');
        PART.COLUMN_GRIP.apply(grip);
        grip.html(Icons.svg('grip-vertical', { size: 12, strokeWidth: 1.5 }))
            .on('pointerdown', (e) => {
            e.preventDefault();
            e.stopPropagation();
            ctx.startPanelColumnDrag(name, e);
        });
        if (ctx.pinnedLeft.includes(name)) item.attr('data-pin', 'left');
        else if (ctx.pinnedRight.includes(name)) item.attr('data-pin', 'right');

        const checkbox = item.find('input');
        checkbox.attr('type', 'checkbox');
        checkbox.prop('checked', ctx.columnOrder.includes(name));
        checkbox.on('change', () => ctx.toggleColumnVisibility(name, checkbox[0].checked));
        item.find('span:last-child').text(label);

        columnList.append(item);
    };

    if (ctx.columnGroups.length) {
        const grouped = new Set();
        ctx.columnGroups.forEach(g => {
            const groupLabel = razyui.spell('div.grid-table-column-group(span)', true);
            PART.COLUMN_GROUP.apply(groupLabel);
            groupLabel.attr('data-group-label', g.label);
            groupLabel.find('span').text(g.label);
            columnList.append(groupLabel);
            (g.columns || []).forEach(col => { grouped.add(col); buildItem(col, 1, g.label); });
        });
        ctx.allColumns.forEach(name => { if (!grouped.has(name)) buildItem(name, 0); });
    } else {
        ctx.allColumns.forEach(name => buildItem(name, 0));
    }
}

/**
 * Rebuild the column list in the side panel after reorder.
 * @param {Object} ctx
 */
export function rebuildPanelColumnList(ctx) {
    const columnList = ctx.sidePanel?.find('.grid-table-column-list');
    if (!columnList?.[0]) return;
    columnList.html('');
    buildColumnList(ctx, columnList);
}

// ═══════════════════════════════════════════════
// Row element
// ═══════════════════════════════════════════════

/**
 * Create a row DOM element with zone structure:
 * toolside | pin-left | checkbox | data | pin-right.
 * @param {Object} ctx
 * @returns {HTMLElement}
 */
export function createRowElement(ctx) {
    const razyui = ctx.razyui;
    const rowParts = [];
    const hasToolside = ctx.showDragHandle || ctx.showRowNumbers || !!ctx.subRowFn;

    // Toolside zone
    if (hasToolside) {
        const tp = [];
        if (ctx.showDragHandle) tp.push('div.$-cell.is-drag-handle');
        if (ctx.showRowNumbers) tp.push('div.$-cell.is-row-number');
        if (ctx.subRowFn) tp.push('div.$-cell.is-expand');
        rowParts.push('div.[$]-toolside(' + tp.join(',') + ')');
    }

    // Pin-left zone
    if (ctx.pinnedLeft.length) {
        rowParts.push('div.[$]-pin-left(div.$-cell*name=' + ctx.pinnedLeft.join('|') + ')');
    } else {
        rowParts.push('div.$-pin-left');
    }

    // Checkbox zone
    if (ctx.showCheckbox) {
        rowParts.push('div.$-checkbox-col(input)');
    }

    // Scrollable data columns (cells created dynamically during render)
    rowParts.push('div.$-data');

    // Pin-right zone
    if (ctx.pinnedRight.length) {
        rowParts.push('div.[$]-pin-right(div.$-cell*name=' + ctx.pinnedRight.join('|') + ')');
    } else {
        rowParts.push('div.$-pin-right');
    }

    const row = razyui.spell('div.[grid-table]-row(' + rowParts.join(',') + ')', true)[0];

    const $row = razyui(row);

    // Apply JIT part classes to row and its sub-zones
    PART.ROW.apply(row);
    const dataEl = $row.find('.grid-table-data')[0];
    if (dataEl) PART.DATA.apply(dataEl);
    $row.find('.grid-table-toolside').each((el) => PART.TOOLSIDE.apply(el));
    $row.find('.grid-table-pin-left').each((el) => PART.PIN_LEFT.apply(el));
    $row.find('.grid-table-pin-right').each((el) => PART.PIN_RIGHT.apply(el));
    $row.find('.grid-table-checkbox-col').each((el) => PART.CHECKBOX_COL.apply(el));

    // Checkbox behaviour
    if (ctx.showCheckbox) {
        const chk = $row.find('.grid-table-checkbox-col input')[0];
        if (chk) {
            chk.type = 'checkbox';
        }
    }

    // Drag handle
    if (ctx.showDragHandle) {
        const $grip = $row.find('.is-drag-handle');
        if ($grip.length) {
            $grip.html(Icons.svg('grip-vertical', { size: 12, strokeWidth: 1.5 }));
        }
    }

    // Expand button
    if (ctx.subRowFn) {
        const $btn = $row.find('.is-expand');
        if ($btn.length) {
            $btn.html(Icons.svg('chevron-right', { size: 12, strokeWidth: 2 })).css('cursor', 'pointer');
        }
    }

    // Build cells map: { colName → Elements wrapper }
    const cells = {};
    $row.find('.grid-table-cell[name]').each(el => {
        cells[el.getAttribute('name')] = razyui(el);
    });

    return { rowElem: row, cells };
}

// ═══════════════════════════════════════════════
// Row data binding
// ═══════════════════════════════════════════════

/**
 * Bind data to a pooled row; create/update reactive cell state.
 * @param {Object} ctx
 * @param {HTMLElement} rowElem
 * @param {number} displayIndex
 * @param {number} poolIndex
 */
export function applyRowData(ctx, rowElem, displayIndex, poolIndex) {
    const razyui = ctx.razyui;
    const entry = ctx.displayList[displayIndex];
    if (!entry) return;
    const dataIndex = entry.dataIndex;
    const isChild = !!entry.childItem;
    const item = isChild ? entry.childItem : (ctx.data[dataIndex] || {});

    const $row = razyui(rowElem);
    $row.setAttr({'data-index': dataIndex, 'data-expansion-key': entry.expansionKey});

    // Toggle child-row class & per-level indent
    $row.toggleClass('is-child-row', isChild);
    if (isChild) {
        $row.css('--indent-level', entry.level);
    } else {
        $row.css('--indent-level', '');
    }

    // Position within visible chunk (skip in no-vscroll — rows flow naturally via CSS)
    if (ctx.enableVscroll) {
        const offsetInChunk = (ctx.rowOffsets[ctx.visibleStart + poolIndex] || 0) - (ctx.rowOffsets[ctx.visibleStart] || 0);
        $row.css('top', offsetInChunk + 'px');
    }

    // Fixed columns
    if (ctx.showRowNumbers) {
        const $numCell = $row.find('.is-row-number');
        if ($numCell.length) {
            $numCell.text(ctx.showSubRowNumbers ? entry.numbering : (isChild ? '' : (dataIndex + 1)));
        }
    }
    if (ctx.showCheckbox) {
        const chk = $row.find('.grid-table-checkbox-col input')[0];
        if (chk) {
            chk.checked = isChild ? false : ctx.selectedRows.has(dataIndex);
            razyui(chk).css('visibility', isChild ? 'hidden' : '');
        }
    }
    if (ctx.subRowFn) {
        const $btn = $row.find('.is-expand');
        if ($btn.length) {
            const children = ctx.subRowFn(item, dataIndex);
            const hasChildren = Array.isArray(children) && children.length > 0;
            $btn.css('visibility', hasChildren ? '' : 'hidden');
            if (hasChildren) {
                $btn.html(ctx.expandedRows.has(entry.expansionKey) ? Icons.svg('chevron-down', { size: 12, strokeWidth: 2 }) : Icons.svg('chevron-right', { size: 12, strokeWidth: 2 }));
            } else {
                $btn.html('');
            }
        }
    }

    // ── Child rows: plain text rendering (no reactive state / components) ──
    if (isChild) {
        const cells = ctx.poolCells[poolIndex];
        const cellCache = ctx.poolCellCache?.[poolIndex] || (ctx.poolCellCache || (ctx.poolCellCache = []))[poolIndex] || ((ctx.poolCellCache[poolIndex] = {}));
        const $dataContainer = $row.find('.grid-table-data');
        
        // Detach cells that are no longer visible — cache for reuse
        const visibleSet = new Set(ctx.visibleColumns);
        for (const colName in cells) {
            if (!visibleSet.has(colName)) {
                cells[colName].detach();
                cellCache[colName] = cells[colName];
                delete cells[colName];
            }
        }

        ctx.visibleColumns.forEach((colName) => {
            let column = cells[colName];
            if (!column) {
                // Try to reuse from cell cache first
                if (cellCache[colName]) {
                    column = cellCache[colName];
                    delete cellCache[colName];
                    $dataContainer.append(column[0]);
                } else {
                    const el = document.createElement('div');
                    el.className = 'grid-table-cell';
                    column = razyui(el).setAttr({name: colName});
                    $dataContainer.append(el);
                }
                const colCfg = ctx.gridColumn[colName];
                if (colCfg) {
                    column.css('left', colCfg.position + 'px').css('width', colCfg.width + 'px');
                }
                cells[colName] = column;
            }
            const val = getNestedValue(item, colName) ?? '';
            const colCfgEntry = ctx.config.columns?.[colName];
            const colOnPrint = colCfgEntry?.onPrint;
            const display = typeof colOnPrint === 'function'
                ? colOnPrint(val)
                : razyui.isPO(val)
                    ? (val.label ?? val.value ?? val.text ?? String(val))
                    : val;
            const el = column[0];
            if (colCfgEntry?.printHTML) {
                column.html(display);
            } else {
                const span = el?.firstElementChild;
                if (span?.tagName === 'SPAN' && span === el.lastElementChild) {
                    razyui(span).text(display);
                } else {
                    column.html('<span></span>');
                    razyui(column[0].firstElementChild).text(display);
                }
            }
        });
        return;
    }

    // ── Parent rows: reactive state + component rendering ──
    let rowState = ctx.rowState[dataIndex];
    if (!rowState) { rowState = {}; ctx.rowState[dataIndex] = rowState; }

    const cells = ctx.poolCells[poolIndex];
    const cellCache = ctx.poolCellCache?.[poolIndex] || (ctx.poolCellCache || (ctx.poolCellCache = []))[poolIndex] || ((ctx.poolCellCache[poolIndex] = {}));
    const $dataContainer = $row.find('.grid-table-data');
    
    // Detach cells that are no longer visible — cache for reuse
    const visibleSet = new Set(ctx.visibleColumns);
    for (const colName in cells) {
        if (!visibleSet.has(colName)) {
            cells[colName].detach();
            cellCache[colName] = cells[colName];
            delete cells[colName];
        }
    }

    ctx.visibleColumns.forEach((colName) => {
        let column = cells[colName];
        if (!column) {
            // Try to reuse from cell cache first
            if (cellCache[colName]) {
                column = cellCache[colName];
                delete cellCache[colName];
                $dataContainer.append(column[0]);
            } else {
                const el = document.createElement('div');
                el.className = 'grid-table-cell';
                column = razyui(el).setAttr({name: colName});
                $dataContainer.append(el);
            }
            const colCfg = ctx.gridColumn[colName];
            if (colCfg) {
                column.css('left', colCfg.position + 'px').css('width', colCfg.width + 'px');
            }
            cells[colName] = column;
        }
        const colCfg = ctx.config.columns?.[colName] || {};
        const compName = colCfg.component;
        // Mark component cells for compact padding
        if (compName) column.addClass('has-component');
        else column.removeClass('has-component');
        const compCfg = colCfg.componentConfig || {};

        if (!rowState[colName]) {
            let _syncing = false;
            let [, setState] = razyui.state({
                value: getNestedValue(item, colName) ?? '',
                element: column,
                _component: null,
                _componentEl: null,
            }).effect(function () {
                if (!this.element) return;

                // Control component integration
                if (compName && razyui[compName]) {
                    // If pool slot changed, the old component is detached — re-create it
                    if (this._component && this._componentEl !== this.element[0]) {
                        if (this._component.destroy) this._component.destroy();
                        this._component = null;
                    }
                    if (!this._component) {
                        let seed;
                        if (compName === 'Combobox') {
                            seed = razyui.spell('select', true);
                            const opts = compCfg.options || colCfg.componentOptions || [];
                            opts.forEach(o => {
                                const opt = razyui.el('option', {
                                    value: typeof o === 'string' ? o : (o.value ?? ''),
                                    textContent: typeof o === 'string' ? o : (o.text ?? o.label ?? ''),
                                    disabled: !!o.disabled,
                                });
                                seed.append(opt);
                            });
                        } else if (compName === 'Chart' || compName === 'Slider' || compName === 'ColorPicker') {
                            seed = razyui.spell('div', true);
                        } else {
                            seed = razyui.spell('input', true);
                        }
                        this.element.html('').append(seed);

                        const onCellChange = (newValue) => {
                            if (_syncing) return;
                            setState({ value: newValue });
                            if (typeof colCfg.onCellChange === 'function') {
                                colCfg.onCellChange(dataIndex, colName, newValue);
                            }
                        };

                        const merged = { ...compCfg, renderContext: 'grid-cell' };
                        if (compName === 'ClipBox' || compName === 'Slider' || compName === 'DatePicker' || compName === 'ColorPicker') {
                            merged.onChange = onCellChange;
                        } else if (compName === 'DynamicSearch') {
                            merged.onSelect = (item, val) => {
                                const label = typeof compCfg.label === 'function'
                                    ? compCfg.label(item)
                                    : (typeof compCfg.label === 'string'
                                        ? (item[compCfg.label] ?? '')
                                        : (item.name ?? item.label ?? item.text ?? ''));
                                onCellChange({ value: val, label });
                            };
                        } else {
                            merged.onSelect = (...args) => onCellChange(args.length > 1 ? args[1] : args[0]);
                        }

                        this._component = new razyui[compName](seed[0], merged);
                        this._componentEl = this.element[0];
                    }
                    // Sync value to component
                    _syncing = true;
                    const ctrl = this._component.getControl?.();
                    if (ctrl) {
                        if (compName === 'Chart') {
                            const chartData = this.value;
                            if (Array.isArray(chartData)) {
                                ctrl.setData([{ data: chartData }]);
                            } else if (razyui.isPO(chartData)) {
                                ctrl.update(chartData);
                            }
                        } else if (ctrl.chips !== undefined) {
                            ctrl.chips = Array.isArray(this.value)
                                ? this.value.map(v => typeof v === 'string' ? { value: v, label: v } : v)
                                : [];
                        } else if (ctrl.forceValue) {
                            const v = this.value;
                            if (razyui.isPO(v) && 'label' in v) {
                                ctrl.forceValue(v.value ?? '', v.label ?? '');
                            } else {
                                ctrl.forceValue(v ?? '', String(v ?? ''));
                            }
                        } else if ('value' in ctrl) {
                            ctrl.value = this.value;
                        }
                    }
                    _syncing = false;
                    // onPrint for component column: pass (data, ctrl)
                    if (typeof colCfg.onPrint === 'function') {
                        colCfg.onPrint(this.value, ctrl);
                    }
                } else {
                    // Plain text render (or HTML if printHTML is set)
                    const val = typeof colCfg.onPrint === 'function'
                        ? colCfg.onPrint(this.value)
                        : (this.value ?? '');
                    if (colCfg.printHTML) {
                        setContent(this.element, val);
                    } else {
                        const span = this.element[0]?.firstElementChild;
                        if (span?.tagName === 'SPAN' && span === this.element[0].lastElementChild) {
                            razyui(span).text(val);
                        } else {
                            this.element.html('<span></span>');
                            razyui(this.element[0].firstElementChild).text(val);
                        }
                    }
                }
            });
            rowState[colName] = setState;
        } else {
            rowState[colName]({ element: column, value: getNestedValue(item, colName) ?? '' });
        }
    });
}

// ═══════════════════════════════════════════════
// Pagination footer
// ═══════════════════════════════════════════════

/**
 * Render the pagination footer.
 * @param {Object} ctx
 */
export function renderFooter(ctx) {
    if (!ctx.ajax || !ctx.footerEl) return;
    ctx.footerEl.css('display', 'flex').html('');

    const total = ctx.ajaxTotal;
    const pageSize = ctx.ajax.pageSize;
    const totalPages = Math.max(1, Math.ceil(total / pageSize));
    const page = ctx.ajaxPage;

    // Info text
    const start = Math.min((page - 1) * pageSize + 1, total);
    const end = Math.min(page * pageSize, total);
    const info = razyui.el('span', {
        className: 'grid-table-footer-info',
        textContent: total > 0 ? `${start}\u2013${end} of ${total}` : 'No records',
    });
    PART.FOOTER_INFO.apply(info);
    ctx.footerEl.append(info);

    // Page buttons
    const nav = razyui.el('div', { className: 'grid-table-footer-nav' });
    PART.FOOTER_NAV.apply(nav);

    const makeBtn = (label, targetPage, disabled) => {
        return razyui.el('button', {
            type: 'button', innerHTML: label, disabled,
            'data-page': targetPage,
        });
    };

    nav.append(makeBtn(Icons.svg('chevron-left', { size: 14, strokeWidth: 2 }), page - 1, page <= 1));

    const maxButtons = MAX_PAGE_BUTTONS;
    let startPage = Math.max(1, page - Math.floor(maxButtons / 2));
    let endPage = Math.min(totalPages, startPage + maxButtons - 1);
    if (endPage - startPage + 1 < maxButtons) {
        startPage = Math.max(1, endPage - maxButtons + 1);
    }

    if (startPage > 1) {
        nav.append(makeBtn('1', 1, false));
        if (startPage > 2) {
            nav.append(razyui.el('span', { className: 'grid-table-footer-dots', textContent: '\u2026' }));
        }
    }
    for (let p = startPage; p <= endPage; p++) {
        const btn = makeBtn(String(p), p, false);
        if (p === page) btn.addClass('is-active');
        nav.append(btn);
    }
    if (endPage < totalPages) {
        if (endPage < totalPages - 1) {
            nav.append(razyui.el('span', { className: 'grid-table-footer-dots', textContent: '\u2026' }));
        }
        nav.append(makeBtn(String(totalPages), totalPages, false));
    }

    nav.append(makeBtn(Icons.svg('chevron-right', { size: 14, strokeWidth: 2 }), page + 1, page >= totalPages));
    ctx.footerEl.append(info).append(nav);
}

// ═══════════════════════════════════════════════
// Column context menu
// ═══════════════════════════════════════════════

/**
 * Show a floating context menu for a column header.
 * @param {Object} ctx
 * @param {string} name — column name
 * @param {number} x
 * @param {number} y
 */
export function showColumnContextMenu(ctx, name, x, y) {
    closeContextMenu(ctx);
    const isPinnedLeft = ctx.pinnedLeft.includes(name);
    const isPinnedRight = ctx.pinnedRight.includes(name);
    const currentPin = isPinnedLeft ? 'left' : isPinnedRight ? 'right' : null;

    const menu = razyui.el('div', { className: 'grid-table-context-menu' });
    PART.CONTEXT_MENU.apply(menu);

    const item = (icon, label, action, opts = {}) => {
        const html = `<span class="grid-table-context-icon">${icon}</span><span class="grid-table-context-label">${label}</span>`
            + (opts.arrow ? '<span class="grid-table-context-arrow">\u25B8</span>' : '');
        const row = razyui.el('div', {
            className: 'grid-table-context-item' + (opts.cls ? ' ' + opts.cls : ''),
            innerHTML: html,
        });
        PART.CONTEXT_ITEM.apply(row);
        row.find('.grid-table-context-icon').each(el => PART.CONTEXT_ICON.apply(el));
        row.find('.grid-table-context-label').each(el => PART.CONTEXT_LABEL.apply(el));
        row.find('.grid-table-context-arrow').each(el => PART.CONTEXT_ARROW.apply(el));
        if (action) row[0]._gtAction = action;
        return row;
    };

    // Sort options (skip for component columns)
    const isComponentCol = !!ctx.columnConfig[name]?.component;
    if (!isComponentCol) {
        const isAsc = ctx.sortState?.column === name && ctx.sortState.direction === 'asc';
        const isDesc = ctx.sortState?.column === name && ctx.sortState.direction === 'desc';
        menu.append(item(isAsc ? '\u2713' : '', 'Sort Ascending', () => {
            ctx.sortState = isAsc ? null : { column: name, direction: 'asc' };
            if (ctx.ajax) {
                ctx.ajaxPage = 1;
                ctx.updateSortIndicators();
                ctx.ajaxFetch();
                return;
            }
            ctx.sortedIndices = null;
            ctx.applySortOrder();
            ctx.updateSortIndicators();
            ctx.visibleStart = -1;
            ctx.visibleEnd = -1;
            ctx.scheduleRender(true);
            ctx.saveState();
        }));
        menu.append(item(isDesc ? '\u2713' : '', 'Sort Descending', () => {
            ctx.sortState = isDesc ? null : { column: name, direction: 'desc' };
            if (ctx.ajax) {
                ctx.ajaxPage = 1;
                ctx.updateSortIndicators();
                ctx.ajaxFetch();
                return;
            }
            ctx.sortedIndices = null;
            ctx.applySortOrder();
            ctx.updateSortIndicators();
            ctx.visibleStart = -1;
            ctx.visibleEnd = -1;
            ctx.scheduleRender(true);
            ctx.saveState();
        }));
    }

    // Pin Column submenu (only when enablePinning is active)
    if (ctx._pinInstalled) {
        if (!isComponentCol) {
            const sep1 = razyui.el('div', { className: 'grid-table-context-sep' });
            PART.CONTEXT_SEP.apply(sep1);
            menu.append(sep1);
        }
        const pinItem = item('\u{1F4CC}', 'Pin Column', null, { arrow: true, cls: 'has-submenu' });
        const pinSub = razyui.el('div', { className: 'grid-table-context-submenu' });
        PART.CONTEXT_SUBMENU.apply(pinSub);

        const pinOpt = (label, side) => {
            const isActive = (side === null && !currentPin) || side === currentPin;
            const opt = razyui.el('div', {
                className: 'grid-table-context-item',
                innerHTML: `<span class="grid-table-context-check">${isActive ? '\u2713' : ''}</span><span class="grid-table-context-label">${label}</span>`,
            });
            PART.CONTEXT_ITEM.apply(opt);
            opt.find('.grid-table-context-check').each(el => PART.CONTEXT_CHECK.apply(el));
            opt.find('.grid-table-context-label').each(el => PART.CONTEXT_LABEL.apply(el));
            opt[0]._gtAction = () => {
                if (side === null) {
                    ctx.unpinColumn(name);
                } else if (!currentPin) {
                    ctx.pinColumn(name, side);
                } else {
                    ctx.unpinColumn(name);
                    if (side) ctx.pinColumn(name, side);
                }
            };
            return opt;
        };
        pinSub.append(pinOpt('No Pin', null))
              .append(pinOpt('Pin Left', 'left'));
        pinSub.append(pinOpt('Pin Right', 'right'));
        pinItem.append(pinSub);
        menu.append(pinItem);
    }

    if (!isComponentCol || ctx._pinInstalled) {
        const sep2 = razyui.el('div', { className: 'grid-table-context-sep' });
        PART.CONTEXT_SEP.apply(sep2);
        menu.append(sep2);
    }
    const sep3 = razyui.el('div', { className: 'grid-table-context-sep' });
    PART.CONTEXT_SEP.apply(sep3);
    menu.append(item('', 'Autosize This Column', () => ctx.autoFitColumn(name)))
        .append(item('', 'Autosize All Columns', () => { ctx.autoSized = false; ctx.autoSizeColumns(); }))
        .append(sep3)
        .append(item('\u{1F5C2}', 'Choose Columns', () => ctx.openPanel('columns')));
    menu.append(item('', 'Reset Columns', () => ctx.resetColumns()));

    // Delegated click handler for context menu actions
    ctx.bindContextMenuActions(menu);

    // Position and mount (inside container so --gt-* tokens are inherited)
    ctx.container.append(menu[0]);
    ctx.contextMenu = menu;

    const rect = menu.getRect();
    if (x + rect.width > window.innerWidth) x = window.innerWidth - rect.width - 4;
    if (y + rect.height > window.innerHeight) y = window.innerHeight - rect.height - 4;
    menu.css('left', x + 'px')
        .css('top', y + 'px');

    // Close on outside click
    const onOutside = (e) => {
        if (!menu.contains(e.target)) {
            closeContextMenu(ctx);
            document.removeEventListener('mousedown', onOutside, true);
        }
    };
    requestAnimationFrame(() => {
        document.addEventListener('mousedown', onOutside, true);
    });
}

/**
 * Close any open context menu.
 * @param {Object} ctx
 */
export function closeContextMenu(ctx) {
    if (ctx.contextMenu) {
        ctx.contextMenu[0].remove();
        ctx.contextMenu = null;
    }
}
